import { axios, store } from './config/axios-config'

const getMunicipios = async (estadoSelecionado) => {

    store.dispatch({ type: 'SET_ESTADO_SELECIONADO', estado: estadoSelecionado })

    const response = await axios.post('/listaMunicipios', {estado: estadoSelecionado.sigla})

    store.dispatch({ type: 'SET_MUNICIPIOS', list: response.data })

}

export default getMunicipios