import React, { useState } from 'react';
import {Button, Pagination} from 'react-bootstrap';
import {Dropdown} from 'react-bootstrap';
import { Link } from 'react-router-dom'
import { useSelector, useDispatch } from 'react-redux'
import Select from 'react-select'

import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import { faEdit } from '@fortawesome/free-solid-svg-icons'


import Aux from "../../../../../hoc/_Aux";
import DEMO from "../../../../../store/constant";

import getMunicipios from '../../../../../connection/getMunicipios'

import './index.css'


const NavRight = (props) => {

    const cursoSelecionado = useSelector(state => state.cursoSelecionado)
    const anoSelecionado = useSelector(state => state.anoSelecionado)
    const listaEstados = useSelector(state => state.listaEstados)
    const listaMunicipios = useSelector(state => state.listaMunicipios)
    const listaAnos = useSelector(state => state.listaAnos)
    const dispach = useDispatch()

    const [selectEstadoValue, setSelectEstadoValue] = useState({value: {cod: "all", sigla: "all"}, label: "Todos os Estados"})
    const [selectMunicipioValue, setSelectMunicipioValue] = useState({value: "all", label: "Todos os Municípios"})
    // const [height, setHeight] = useState(0)
    
    // useEffect(() => {
    //     console.log('to aqui')
    //     setHeight(navbarRef.current.clientHeight)
    // })

    let render = render = (
        <ul className="navbar-nav ml-auto">
            
        </ul>
    )

    const changeYear = (year) => {
        dispach({ type: 'CHANGE_YEAR', year }) 
    }


    let navItemClass = ['nav-item'];
    if (props.windowWidth <= 575) {
        navItemClass = [...navItemClass, 'd-none'];
    }
    let dropdownRightAlign = false;
    if (props.rtlLayout) {
        dropdownRightAlign = true;
    }

    if(cursoSelecionado !== ""){
        const anos = listaAnos.map((year) => {
            if(year === anoSelecionado)
                return <Pagination.Item className='yearPagination' onClick={() => { changeYear(year) }} active='true'>{year}</Pagination.Item>

            return <Pagination.Item onClick={() => { changeYear(year) }} className='yearPagination'>{year}</Pagination.Item>
        })
        render = (
            <Aux>
                <div className='navbarContainer'>
                    <div className='navbarContainerTitle'>
                        <Link to="/curso">
                            <div className='navbarTitle'>
                                {cursoSelecionado !== "" ? cursoSelecionado.NO_CINE_ROTULO:"Curso de Graduação"}
                                <FontAwesomeIcon className='editCourseIcon' icon={faEdit}/>
                            </div>
                        </Link>
                    </div>
                    <div className={`navbarContainerRow`}>
                        <div className='navbarContainerLeft'>
                            <Select 
                                options={
                                    listaEstados.map((estado)=>{
                                        return {value: {cod: estado.COD, sigla: estado.SIGLA}, label: estado.NOME}
                                    })
                                }
                                onChange={(e) => {
                                    setSelectEstadoValue(e)
                                    getMunicipios(e.value)
                                }}
                                value={selectEstadoValue}
                                className="combobox"
                                placeholder="Selecione um estado"
                            />

                            <Select 
                                options={
                                    listaMunicipios.map((municipio)=>{
                                        return {value: municipio.col_cod, label: municipio.col_municipio}
                                    })
                                }
                                onChange={(e) => {
                                    setSelectMunicipioValue(e)
                                    dispach({ type: 'SET_MUNICIPIO_SELECIONADO', value: e.value }) 
                                }}
                                value={selectMunicipioValue}
                                className="combobox"
                                placeholder="Selecione um município"
                            />
                            
                        </div>
                        <div className='navbarContainerRight'>
                            <Pagination>
                                {anos}
                            </Pagination>
                        </div>
                    </div>
                </div>
            </Aux>
        )
    }
        
    
    

    return (
        <Aux>
            {render}
        </Aux>
    );
    
}

export default NavRight;
