import React, {Component} from 'react';
import {connect} from 'react-redux';
import {Dropdown} from 'react-bootstrap';
import windowSize from 'react-window-size';

import { Link } from 'react-router-dom'

import Aux from "../../../../../hoc/_Aux";
import DEMO from "../../../../../store/constant";
import * as actionTypes from "../../../../../store/actions";

class NavLeft extends Component {

    render() {
        let iconFullScreen = ['feather'];
        iconFullScreen = (this.props.isFullScreen) ? [...iconFullScreen, 'icon-minimize'] : [...iconFullScreen, 'icon-maximize'];

        let navItemClass = ['nav-item'];
        if (this.props.windowWidth <= 575) {
            navItemClass = [...navItemClass, 'd-none'];
        }
        let dropdownRightAlign = false;
        if (this.props.rtlLayout) {
            dropdownRightAlign = true;
        }

        const dropdownMenu = () => {
            if(this.props.cursoSelecionado === "")
                return (
                    <li><Link to="/curso/" className="dropdown-item">Selecionar um Curso</Link></li>
                )
            
            return (
                <>
                    <li><Link to="/curso/" className="dropdown-item">Trocar Curso</Link></li>
                    <li><Link to="/ocupacoes" className="dropdown-item">Ocupações do Curso</Link></li>
                    <li><Link to="/ies" className="dropdown-item">Escolher IES</Link></li>
                    <li><Link to="/emconstrucao" className="dropdown-item">Adicionar Custo Total do Curso</Link></li>
                </>
                
            )
        }

        return (
            <Aux>
                <ul className="navbar-nav mr-auto">
                    <li><a href={DEMO.BLANK_LINK} className="full-screen" onClick={this.props.onFullScreen}><i className={iconFullScreen.join(' ')} /></a></li>
                    <li className={navItemClass.join(' ')}>
                        <Dropdown alignRight={dropdownRightAlign}>
                            <Dropdown.Toggle variant={'link'} id="dropdown-basic">
                                {this.props.cursoSelecionado !== "" ? this.props.cursoSelecionado.NO_CINE_ROTULO:"Curso de Graduação"}
                            </Dropdown.Toggle>
                            <ul>
                                <Dropdown.Menu>
                                    {dropdownMenu()}
                                </Dropdown.Menu>
                            </ul>
                        </Dropdown>
                    </li>
                    {/* <li className="nav-item"><NavSearch/></li> */}
                </ul>
            </Aux>
        );
    }
}

const mapStateToProps = state => {
    return {
        isFullScreen: state.isFullScreen,
        rtlLayout: state.rtlLayout,
        cursoSelecionado: state.cursoSelecionado
    }
};

const mapDispatchToProps = dispatch => {
    return {
        onFullScreen: () => dispatch({type: actionTypes.FULL_SCREEN}),
    }
};

export default connect(mapStateToProps, mapDispatchToProps)(windowSize(NavLeft));
